const calculateClaimPayout = (policy: any, incident: any): { payout: number; remainingCap: number } => {
  const insuranceSum = policy.items.reduce(
    (sum: number, item: any) => sum + insuranceValue(item), 0
  );
  const cap = insuranceSum * 2;
  let totalPayout = 0;
  for (const damage of incident.damages) {
    const payout = damage.amount - DEDUCTIBLE;
    totalPayout += payout;
  }
  return { payout: totalPayout, remainingCap: cap - totalPayout };
};

export const processScenario = (scenario: any): any => {
  let quoteCount = 0;
  const policies: any[] = [];
  const results = scenario.steps.map((step: any, index: number) => {
    if (step.op === "claim") {
      return calculateClaimPayout(policies[step.policy], step.incident);
    }
    policies[index] = { items: step.items };
    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount > 0);
    quoteCount++;
    return { premium };
  });
  return { results };
};

