62	const INSURANCE_VALUES: Record<string, number> = {
63	  sword: 1000,
64	  amulet: 600,
65	  staff: 800,
66	  potion: 400,
67	};
68	
69	const DEDUCTIBLE = 100;
70	
71	const insuranceValue = (item: any): number => {
72	  if (isComponent(item)) return 250;
73	  return INSURANCE_VALUES[item.type] ?? 0;
74	};
75	
76	const calculateClaimPayout = (policy: any, incident: any): { payout: number; remainingCap: number } => {
77	  const insuranceSum = policy.items.reduce(
78	    (sum: number, item: any) => sum + insuranceValue(item), 0
79	  );
80	  const cap = insuranceSum * 2;
81	  let totalPayout = 0;
82	  for (const damage of incident.damages) {
83	    const payout = damage.amount - DEDUCTIBLE;
84	    totalPayout += payout;
85	  }
86	  return { payout: totalPayout, remainingCap: cap - totalPayout };
87	};
