89	export const processScenario = (scenario: any): any => {
90	  let quoteCount = 0;
91	  const policies: any[] = [];
92	  const results = scenario.steps.map((step: any, index: number) => {
93	    if (step.op === "claim") {
94	      return calculateClaimPayout(policies[step.policy], step.incident);
95	    }
96	    policies[index] = { items: step.items };
97	    const premium = calculateQuotePremium(step.items, scenario.customer, quoteCount > 0);
98	    quoteCount++;
99	    return { premium };
100	  });
101	  return { results };
102	};
